import React from "react";

interface Props {
 id: number;
 name: string;
 weight: string;
 price: number;
 oldPrice?: number;
 discount?: string;
 image: string;
 onAdd: () => void;
}

const ProductCard: React.FC<Props> = ({ name, weight, price, oldPrice, discount, image, onAdd }) => (
 <div
  className="group"
  style={{
   background: "#fff",
   padding: "24px 20px 32px",
   display: "flex",
   flexDirection: "column",
   position: "relative",
   cursor: "pointer",
   transition: "all 0.4s var(--ease-out)",
  }}
  onMouseEnter={e => {
   e.currentTarget.style.background = "var(--meren-bone)";
   e.currentTarget.style.zIndex = "10";
   e.currentTarget.style.boxShadow = "inset 0 0 0 2px var(--meren-black)";
  }}
  onMouseLeave={e => {
   e.currentTarget.style.background = "#fff";
   e.currentTarget.style.zIndex = "auto";
   e.currentTarget.style.boxShadow = "none";
  }}
 >
  {/* ── Bold Discount Badge ── */}
  {discount && (
   <span style={{
    position: "absolute", top: 16, right: 16, zIndex: 10,
    background: "var(--meren-black)", color: "#fff",
    fontFamily: "var(--font-manrope)", fontSize: 11, fontWeight: 900,
    padding: "4px 8px", borderRadius: 4, letterSpacing: "0.05em",
   }}>
    {discount}
   </span>
  )}

  {/* ── Image with Organic Background ── */}
  <div style={{
   position: "relative", aspectRatio: "1", display: "flex",
   alignItems: "center", justifyContent: "center",
   background: "var(--meren-dark-bone)",
   borderRadius: "45% 55% 50% 50% / 55% 45% 55% 45%",
   overflow: "hidden", marginBottom: 24,
   transition: "all 0.6s var(--ease-out)",
  }}
   className="group-hover:[transform:rotate(2deg)_scale(1.05)]"
  >
   <img
    src={image} alt={name} loading="lazy"
    style={{ width: "85%", height: "85%", objectFit: "contain", mixBlendMode: "multiply", filter: "contrast(1.1)" }}
   />
  </div>

  {/* ── Product Info ── */}
  <div style={{ display: "flex", flexDirection: "column", flex: 1 }}>
   <p style={{
    fontFamily: "var(--font-manrope)", fontSize: 14, fontWeight: 800,
    color: "var(--meren-black)", lineHeight: 1.1, letterSpacing: "-0.04em",
    textTransform: "lowercase", marginBottom: 4, height: 32, overflow: "hidden"
   }}>
    {name}
   </p>

   <p style={{
    fontFamily: "var(--font-manrope)", fontSize: 11, fontWeight: 700,
    color: "var(--fg-muted)", textTransform: "uppercase", letterSpacing: "0.1em",
   }}>
    {weight}
   </p>

   {/* ── Price Row ── */}
   <div style={{ marginTop: "auto", paddingTop: 16, display: "flex", alignItems: "flex-end", justifyContent: "space-between" }}>
    <div style={{ display: "flex", flexDirection: "column" }}>
     {oldPrice && (
      <span style={{
       fontFamily: "var(--font-manrope)", fontSize: 13, fontWeight: 700,
       color: "var(--fg-muted)", textDecoration: "line-through", marginBottom: -4,
      }}>
       {oldPrice}
      </span>
     )}
     <span style={{
      fontFamily: "var(--font-manrope)", fontSize: 32, fontWeight: 900,
      letterSpacing: "-0.06em", color: "var(--meren-black)", lineHeight: 0.8,
     }}>
      {price}
     </span>
    </div>

    {/* ── Spring Add Button ── */}
    <button
     onClick={(e) => { e.stopPropagation(); onAdd(); }}
     style={{
      width: 44, height: 44, borderRadius: "50%",
      background: "var(--meren-orange)", border: "none",
      display: "flex", alignItems: "center", justifyContent: "center",
      cursor: "pointer", color: "#fff",
      transition: "all 0.3s var(--ease-spring)",
     }}
     onMouseEnter={e => e.currentTarget.style.transform = "rotate(90deg) scale(1.1)"}
     onMouseLeave={e => e.currentTarget.style.transform = "none"}
    >
     <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="4">
      <path d="M12 5v14M5 12h14" />
     </svg>
    </button>
   </div>
  </div>
 </div>
);

export default ProductCard;
