"use client";

import React, { useState } from "react";
import Header from "@/components/Header";
import ProductCard from "@/components/ProductCard";
import CartSidebar from "@/components/CartSidebar";
import PromoBanners from "@/components/PromoBanners";
import { products } from "@/components/data";

export interface CartItem {
 id: number;
 name: string;
 image: string;
 price: number;
 oldPrice?: number;
 quantity: number;
}

export default function Home() {
 const [cart, setCart] = useState<CartItem[]>([]);

 const addToCart = (product: typeof products[0]) => {
  setCart((prev) => {
   const found = prev.find((i) => i.id === product.id);
   if (found) return prev.map((i) => i.id === product.id ? { ...i, quantity: i.quantity + 1 } : i);
   return [...prev, {
    id: product.id, name: product.name, image: product.image ?? "",
    price: product.price, oldPrice: product.oldPrice, quantity: 1,
   }];
  });
 };

 const updateQty = (id: number, delta: number) => {
  setCart((prev) =>
   prev.map((i) => i.id === id ? { ...i, quantity: Math.max(0, i.quantity + delta) } : i)
    .filter((i) => i.quantity > 0)
  );
 };

 const total = cart.reduce((s, i) => s + i.price * i.quantity, 0);

 return (
  <div className="min-h-screen font-manrope" style={{ background: "var(--meren-bone)" }}>
   <Header />

   <div style={{ display: "flex", maxWidth: "100%" }}>

    {/* ═══ Left gray panel ═══ */}
    <aside
     className="hidden xl:block shrink-0 sticky top-[80px]"
     style={{
      width: 130,
      height: "calc(100vh - 80px)",
      background: "linear-gradient(180deg, #E6E6EA 0%, #DCDCE2 100%)",
     }}
    />

    {/* ═══ Center: everything ═══ */}
    <div style={{ flex: 1, minWidth: 0, padding: "28px 24px" }}>

     {/* Banners — full width */}
     <PromoBanners />

     {/* Below banners: product grid + cart float side by side */}
     <div style={{ display: "flex", gap: 24, alignItems: "flex-start" }}>

      {/* ── Product column ── */}
      <div style={{ flex: 1, minWidth: 0 }}>
       <h2 style={{
        fontFamily: "var(--font-manrope)",
        fontSize: 22, fontWeight: 900,
        letterSpacing: "-0.04em", color: "var(--meren-black)",
        textTransform: "lowercase", marginBottom: 16,
       }}>
        товары
       </h2>

       {/* 5-column grid */}
       <div style={{
        display: "grid",
        gridTemplateColumns: "repeat(5, 1fr)",
        background: "rgba(0,0,0,0.07)",
        gap: "1px",
        borderRadius: 24,
        overflow: "hidden",
       }}>
        {products.map((p) => (
         <ProductCard
          key={p.id}
          {...p}
          image={p.image ?? ""}
          onAdd={() => addToCart(p)}
         />
        ))}

        {/* "Больше" tile */}
        <div
         className="group flex flex-col items-center justify-center cursor-pointer"
         style={{ background: "#fff", minHeight: 200, transition: "background 0.2s" }}
         onMouseEnter={e => e.currentTarget.style.background = "#F5F5F7"}
         onMouseLeave={e => e.currentTarget.style.background = "#fff"}
        >
         <div style={{
          fontSize: 12, fontWeight: 800, color: "#8E8E93",
          textTransform: "lowercase", textAlign: "center",
         }}>
          Больше →
         </div>
        </div>
       </div>
      </div>

      {/* ── Cart — floating, sticky to top ── */}
      <div
       className="hidden lg:block shrink-0"
       style={{
        width: 320,
        position: "sticky",
        top: 96, /* header 80px + 16px gap */
        maxHeight: "calc(100vh - 110px)",
        overflowY: "auto",
       }}
      >
       <CartSidebar cart={cart} onUpdateQuantity={updateQty} total={total} />
      </div>

     </div>
    </div>
   </div>
  </div>
 );
}
