"use client";
import React from "react";

const PromoBanners = () => (
 <div style={{ display: "grid", gridTemplateColumns: "repeat(3, 1fr)", gap: 16, marginBottom: 40 }}>

  {/* ═══ Story 1 — Orange Intensity ═══ */}
  <div
   className="group anim-slide-up"
   style={{
    position: "relative",
    height: 480,
    borderRadius: 32,
    background: "var(--meren-orange)",
    padding: 32,
    overflow: "hidden",
    display: "flex",
    flexDirection: "column",
    justifyContent: "space-between",
   }}
  >
   <div style={{ position: "relative", zIndex: 5 }}>
    <p style={{
     fontSize: 12, fontWeight: 800, textTransform: "uppercase",
     letterSpacing: "0.2em", color: "rgba(255,255,255,0.7)", marginBottom: 16
    }}>
     экспертный контент
    </p>
    <h2 style={{
     fontSize: 32, fontWeight: 900, color: "#fff",
     maxWidth: "200px", lineHeight: 0.9, marginBottom: 24
    }}>
     приглашение на работу от руководителей
    </h2>
   </div>

   {/* Organic Mask Image */}
   <div style={{
    position: "absolute", bottom: -20, left: -20, right: -20,
    height: "65%", display: "flex", justifyContent: "center"
   }}>
    <div style={{
     width: "120%", height: "100%",
     background: "url('https://images.unsplash.com/photo-1556910103-1c02745aae4d?w=800&q=80') center center",
     backgroundSize: "cover",
     filter: "grayscale(100%) brightness(0.9)",
     borderRadius: "50% 50% 10% 10% / 100% 100% 0% 0%",
     transform: "rotate(-3deg)",
     zIndex: 1
    }} />
   </div>

   <div style={{
    display: "flex", justifyContent: "space-between", alignItems: "flex-end",
    position: "relative", zIndex: 10
   }}>
    <div>
     <p style={{ fontSize: 13, fontWeight: 800, color: "#fff" }}>алексей</p>
     <p style={{ fontSize: 11, fontWeight: 700, color: "rgba(255,255,255,0.6)" }}>руководитель производства</p>
    </div>
    <button style={{
     width: 48, height: 48, borderRadius: "50%",
     background: "transparent", border: "2px solid #fff", color: "#fff",
     display: "flex", alignItems: "center", justifyContent: "center",
     cursor: "pointer", transition: "all 0.3s"
    }}
     onMouseEnter={e => {
      e.currentTarget.style.background = "#fff";
      e.currentTarget.style.color = "var(--meren-orange)";
     }}
     onMouseLeave={e => {
      e.currentTarget.style.background = "transparent";
      e.currentTarget.style.color = "#fff";
     }}>
     <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3">
      <path d="M7 17L17 7M17 7H7M17 7V17" />
     </svg>
    </button>
   </div>
  </div>

  {/* ═══ Story 2 — Dark Depth ═══ */}
  <div
   className="group anim-slide-up anim-delay-1"
   style={{
    position: "relative",
    height: 480,
    borderRadius: 32,
    background: "var(--meren-black)",
    padding: 32,
    overflow: "hidden",
    display: "flex",
    flexDirection: "column",
    justifyContent: "space-between",
   }}
  >
   <div style={{ position: "relative", zIndex: 5, textAlign: "center" }}>
    <p style={{
     fontSize: 12, fontWeight: 800, textTransform: "uppercase",
     letterSpacing: "0.2em", color: "rgba(255,255,255,0.4)", marginBottom: 16
    }}>
     профессии буше
    </p>
    <h2 style={{
     fontSize: 48, fontWeight: 900, color: "#fff",
     lineHeight: 0.85, letterSpacing: "-0.05em"
    }}>
     кто есть кто в компании?
    </h2>
   </div>

   {/* Organic Mask Image */}
   <div style={{
    position: "absolute", top: "55%", left: "50%", transform: "translate(-50%, -50%)",
    width: "90%", height: "55%", zIndex: 1
   }}>
    <div style={{
     width: "100%", height: "100%",
     background: "url('https://images.unsplash.com/photo-1507003211169-0a1dd7228f2d?w=800&q=80') center center",
     backgroundSize: "cover",
     filter: "grayscale(100%)",
     borderRadius: "45% 55% 50% 50% / 55% 45% 55% 45%",
     border: "2px solid rgba(255,255,255,0.2)"
    }} />
   </div>

   <div style={{
    display: "flex", justifyContent: "space-between", alignItems: "flex-end",
    position: "relative", zIndex: 10
   }}>
    <div>
     <p style={{ fontSize: 13, fontWeight: 800, color: "#fff" }}>маша</p>
     <p style={{ fontSize: 11, fontWeight: 700, color: "rgba(255,255,255,0.4)" }}>пекарь-слойщик</p>
    </div>
    <button style={{
     width: 48, height: 48, borderRadius: "50%",
     background: "transparent", border: "2px solid #fff", color: "#fff",
     display: "flex", alignItems: "center", justifyContent: "center",
     cursor: "pointer", transition: "all 0.3s"
    }}>
     <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3">
      <path d="M7 17L17 7M17 7H7M17 7V17" />
     </svg>
    </button>
   </div>
  </div>

  {/* ═══ Story 3 — Orange Detail ═══ */}
  <div
   className="group anim-slide-up anim-delay-2"
   style={{
    position: "relative",
    height: 480,
    borderRadius: 32,
    background: "var(--meren-orange)",
    padding: 32,
    overflow: "hidden",
    display: "flex",
    flexDirection: "column",
    justifyContent: "space-between",
   }}
  >
   <div style={{ position: "relative", zIndex: 5 }}>
    <p style={{
     fontSize: 12, fontWeight: 800, textTransform: "uppercase",
     letterSpacing: "0.2em", color: "rgba(255,255,255,0.7)", marginBottom: 16
    }}>
     экспертный контент
    </p>
    <h2 style={{
     fontSize: 42, fontWeight: 900, color: "#fff",
     lineHeight: 0.85, letterSpacing: "-0.04em", maxWidth: "250px"
    }}>
     как придумывать новые блюда
    </h2>
   </div>

   <div style={{
    position: "absolute", bottom: 0, right: 0, width: "100%", height: "60%",
    display: "flex", justifyContent: "flex-end", alignItems: "flex-end"
   }}>
    <div style={{
     width: "90%", height: "100%",
     background: "url('https://images.unsplash.com/photo-1595152772835-219674b2a8a6?w=800&q=80') center center",
     backgroundSize: "cover",
     filter: "grayscale(100%)",
     borderRadius: "80% 0 0 0 / 100% 0 0 0",
    }} />
   </div>

   <div style={{
    display: "flex", justifyContent: "space-between", alignItems: "flex-end",
    position: "relative", zIndex: 10
   }}>
    <div>
     <p style={{ fontSize: 13, fontWeight: 800, color: "#fff" }}>павел</p>
     <p style={{ fontSize: 11, fontWeight: 700, color: "rgba(255,255,255,0.6)" }}>шеф-повар</p>
    </div>
    <button style={{
     width: 48, height: 48, borderRadius: "50%",
     background: "transparent", border: "2px solid #fff", color: "#fff",
     display: "flex", alignItems: "center", justifyContent: "center",
     cursor: "pointer", transition: "all 0.3s"
    }}>
     <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3">
      <path d="M7 17L17 7M17 7H7M17 7V17" />
     </svg>
    </button>
   </div>
  </div>

 </div>
);

export default PromoBanners;
