"use client";
import React from "react";
import { CartItem } from "@/app/page";

interface Props {
 cart: CartItem[];
 onUpdateQuantity: (id: number, delta: number) => void;
 total: number;
}

/* Sad bag illustration — inline SVG */
const SadBag = () => (
 <svg width="100" height="120" viewBox="0 0 100 120" fill="none" xmlns="http://www.w3.org/2000/svg">
  {/* Bag body */}
  <rect x="14" y="36" width="72" height="80" rx="6" fill="#F0F0F0" />
  {/* Bag handle */}
  <path d="M36 36 C36 20 64 20 64 36" stroke="#D0D0D0" strokeWidth="4" fill="none" strokeLinecap="round" />
  {/* Face — × left eye */}
  <path d="M37 68 L43 74 M43 68 L37 74" stroke="#B0B0B0" strokeWidth="3" strokeLinecap="round" />
  {/* Face — × right eye */}
  <path d="M57 68 L63 74 M63 68 L57 74" stroke="#B0B0B0" strokeWidth="3" strokeLinecap="round" />
  {/* Face — flat mouth */}
  <path d="M40 86 L60 86" stroke="#B0B0B0" strokeWidth="3" strokeLinecap="round" />
 </svg>
);

const CartSidebar: React.FC<Props> = ({ cart, onUpdateQuantity, total }) => {
 return (
  <div style={{
   display: "flex",
   flexDirection: "column",
   height: "100%",
   background: "#fff",
   borderRadius: 24,
   overflow: "hidden",
   boxShadow: "0 8px 32px rgba(0,0,0,0.07)",
   border: "1px solid rgba(0,0,0,0.06)",
   fontFamily: "var(--font-manrope)",
  }}>

   {/* ── Top info bar ── */}
   <div style={{
    display: "flex", alignItems: "center", justifyContent: "space-between",
    padding: "18px 20px", borderBottom: "1px solid rgba(0,0,0,0.06)",
   }}>
    <span style={{
     fontSize: 17, fontWeight: 900, color: "#0F0F0F", letterSpacing: "-0.035em",
    }}>
     30–60 мин, 0–219₽
    </span>
    <button style={{
     width: 28, height: 28, background: "none", border: "none", cursor: "pointer",
     display: "flex", alignItems: "center", justifyContent: "center", borderRadius: "50%",
     transition: "background 0.15s",
    }}
     onMouseEnter={e => e.currentTarget.style.background = "#F5F5F5"}
     onMouseLeave={e => e.currentTarget.style.background = "none"}
    >
     <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="#AEAEB2" strokeWidth="2" strokeLinecap="round">
      <circle cx="12" cy="12" r="10" />
      <path d="M12 16v-4M12 8h.01" />
     </svg>
    </button>
   </div>

   {/* ── Body ── */}
   <div style={{ flex: 1, display: "flex", flexDirection: "column" }}>
    {cart.length === 0 ? (
     /* ── Empty state ── */
     <div style={{
      flex: 1, display: "flex", flexDirection: "column",
      alignItems: "center", justifyContent: "center",
      padding: "40px 24px",
     }}>
      <SadBag />
      <p style={{
       marginTop: 20, fontSize: 14, fontWeight: 500, color: "#3C3C43",
       textAlign: "center", lineHeight: 1.5, maxWidth: 200,
      }}>
       В корзине пока ничего нет. Самое время наполнять её!
      </p>
     </div>
    ) : (
     /* ── Items ── */
     <div style={{ flex: 1, overflowY: "auto", padding: "12px 16px 0" }}>
      <div style={{ display: "flex", flexDirection: "column", gap: 12 }}>
       {cart.map((item) => (
        <div key={item.id} style={{
         display: "flex", alignItems: "center", gap: 10,
         padding: "10px 10px", background: "#F9F8F5", borderRadius: 16,
        }}>
         {/* Thumbnail */}
         <div style={{
          width: 50, height: 50, flexShrink: 0, background: "#fff",
          borderRadius: 12, display: "flex", alignItems: "center", justifyContent: "center",
          overflow: "hidden", boxShadow: "0 1px 6px rgba(0,0,0,0.07)",
         }}>
          <img src={item.image} alt="" style={{ width: "80%", height: "80%", objectFit: "contain", mixBlendMode: "multiply" }} />
         </div>

         {/* Name + qty */}
         <div style={{ flex: 1, minWidth: 0 }}>
          <p style={{
           fontSize: 11, fontWeight: 700, color: "#0F0F0F", lineHeight: 1.3,
           marginBottom: 5, overflow: "hidden", display: "-webkit-box",
           WebkitLineClamp: 2, WebkitBoxOrient: "vertical",
          }}>
           {item.name}
          </p>

          {/* — N + */}
          <div style={{
           display: "inline-flex", alignItems: "center",
           background: "#fff", borderRadius: 8,
           border: "1px solid rgba(0,0,0,0.07)",
          }}>
           <button onClick={() => onUpdateQuantity(item.id, -1)} style={{
            width: 26, height: 26, background: "none", border: "none",
            cursor: "pointer", fontSize: 14, fontWeight: 700,
            color: "#AEAEB2", display: "flex", alignItems: "center", justifyContent: "center",
            transition: "color 0.15s",
           }}
            onMouseEnter={e => e.currentTarget.style.color = "var(--meren-orange)"}
            onMouseLeave={e => e.currentTarget.style.color = "#AEAEB2"}
           >—</button>
           <span style={{ fontSize: 12, fontWeight: 900, color: "#0F0F0F", minWidth: 14, textAlign: "center" }}>
            {item.quantity}
           </span>
           <button onClick={() => onUpdateQuantity(item.id, 1)} style={{
            width: 26, height: 26, background: "none", border: "none",
            cursor: "pointer", fontSize: 14, fontWeight: 700,
            color: "#AEAEB2", display: "flex", alignItems: "center", justifyContent: "center",
            transition: "color 0.15s",
           }}
            onMouseEnter={e => e.currentTarget.style.color = "var(--meren-orange)"}
            onMouseLeave={e => e.currentTarget.style.color = "#AEAEB2"}
           >+</button>
          </div>
         </div>

         {/* Price */}
         <div style={{ flexShrink: 0, display: "flex", flexDirection: "column", alignItems: "flex-end" }}>
          {item.oldPrice && (
           <span style={{ fontSize: 10, color: "#C7C7CC", textDecoration: "line-through", fontWeight: 500, marginBottom: 1 }}>
            {item.oldPrice * item.quantity}
           </span>
          )}
          <span style={{ fontSize: 14, fontWeight: 900, color: "#0F0F0F", letterSpacing: "-0.03em" }}>
           {item.price * item.quantity} ₽
          </span>
         </div>
        </div>
       ))}
      </div>

      {/* Total row */}
      <div style={{ padding: "12px 6px", borderTop: "1px solid rgba(0,0,0,0.06)", marginTop: 12, display: "flex", justifyContent: "space-between" }}>
       <span style={{ fontSize: 12, fontWeight: 700, color: "#8E8E93" }}>Итого</span>
       <span style={{ fontSize: 20, fontWeight: 900, letterSpacing: "-0.04em", color: "#0F0F0F" }}>{total} ₽</span>
      </div>
     </div>
    )}
   </div>

   {/* ── Bottom button ── */}
   <div style={{ padding: "12px 16px 18px" }}>
    <button
     disabled={cart.length === 0}
     style={{
      width: "100%", height: 50, borderRadius: 100, border: "none",
      background: cart.length === 0
       ? "#F2F2F7"
       : "linear-gradient(180deg, #E09535 0%, #C47420 100%)",
      color: cart.length === 0 ? "#AEAEB2" : "#fff",
      fontSize: 15, fontWeight: 700,
      fontFamily: "var(--font-manrope)",
      letterSpacing: "-0.01em",
      cursor: cart.length === 0 ? "default" : "pointer",
      boxShadow: cart.length === 0 ? "none" : "0 6px 20px rgba(196,116,32,0.25)",
      transition: "all 0.25s var(--ease-out)",
     }}
     onMouseEnter={e => {
      if (cart.length > 0) e.currentTarget.style.filter = "brightness(1.08)";
     }}
     onMouseLeave={e => e.currentTarget.style.filter = "none"}
    >
     {cart.length === 0 ? "Добавьте что-нибудь" : "Продолжить"}
    </button>
   </div>

  </div>
 );
};

export default CartSidebar;
