"use client";
import React, { useState, useEffect } from "react";
import { SearchIcon, UserIcon } from "./icons";

const Header = () => {
 const [scrolled, setScrolled] = useState(false);

 useEffect(() => {
  const h = () => setScrolled(window.scrollY > 8);
  window.addEventListener("scroll", h, { passive: true });
  return () => window.removeEventListener("scroll", h);
 }, []);

 return (
  <header
   style={{
    height: 80,
    position: "sticky",
    top: 0,
    zIndex: 100,
    display: "flex",
    alignItems: "center",
    padding: "0 40px",
    gap: 32,
    background: scrolled ? "rgba(255,255,255,0.95)" : "var(--meren-bone)",
    backdropFilter: scrolled ? "blur(20px)" : "none",
    borderBottom: `2px solid ${scrolled ? "var(--meren-black)" : "rgba(0,0,0,0.05)"}`,
    transition: "all 0.4s var(--ease-out)",
   }}
  >
   {/* ── Bold Logotype ── */}
   <div style={{ display: "flex", flexDirection: "column", cursor: "pointer", userSelect: "none" }}>
    <span style={{ fontSize: 28, fontWeight: 900, letterSpacing: "-0.08em", lineHeight: 0.7, color: "var(--meren-black)" }}>
     смысл
    </span>
    <span style={{ fontSize: 28, fontWeight: 900, letterSpacing: "-0.08em", lineHeight: 0.7, color: "var(--meren-orange)" }}>
     есть
    </span>
   </div>

   {/* ── Minimalist Search ── */}
   <div style={{ flex: 1, display: "flex", justifyContent: "center" }}>
    <div
     style={{
      display: "flex",
      alignItems: "center",
      gap: 12,
      background: "transparent",
      borderBottom: "2px solid var(--meren-black)",
      padding: "0 8px",
      height: 48,
      width: "100%",
      maxWidth: 400,
      transition: "all 0.3s var(--ease-out)",
     }}
    >
     <SearchIcon size={20} className="text-[var(--meren-black)]" />
     <input
      type="text"
      placeholder="ищем хлеб..."
      style={{
       flex: 1,
       background: "transparent",
       border: "none",
       outline: "none",
       fontFamily: "var(--font-manrope)",
       fontSize: 16,
       fontWeight: 700,
       color: "var(--meren-black)",
       letterSpacing: "-0.02em",
       textTransform: "lowercase",
      }}
     />
    </div>
   </div>

   {/* ── Profile Action ── */}
   <button
    style={{
     width: 48,
     height: 48,
     borderRadius: 12,
     background: "var(--meren-black)",
     border: "none",
     cursor: "pointer",
     display: "flex",
     alignItems: "center",
     justifyContent: "center",
     transition: "transform 0.2s var(--ease-spring)",
    }}
    onMouseEnter={e => e.currentTarget.style.transform = "scale(1.1) rotate(5deg)"}
    onMouseLeave={e => e.currentTarget.style.transform = "scale(1) rotate(0)"}
   >
    <UserIcon size={22} className="text-[var(--meren-bone)]" />
   </button>
  </header>
 );
};

export default Header;
